1	import Alpine from 'alpinejs';
2	import { db } from './firebase';
3	import { collection, query, where, getDocs, addDoc, onSnapshot, doc, updateDoc } from 'firebase/firestore';
4	
5	declare global {
6	  interface Window {
7	    Alpine: any;
8	  }
9	}
10	
11	// Make Alpine available globally
12	window.Alpine = Alpine;
13	
14	document.addEventListener('alpine:init', () => {
15	  Alpine.data('app', () => ({
16	    route: window.location.pathname,
17	    phoneNumber: '',
18	    
19	    // Onboarding State
20	    onboardingStep: 1,
21	    registerName: '',
22	    registerTrade: '',
23	    registerCompany: '',
24	    registerArea: '',
25	    calloutFee: 50,
26	    filterStrictness: 3,
27	    loginError: '',
28	    isLoggingIn: false,
29	    
30	    // Vault State
31	    newVaultIdea: '',
32	    newVaultPhase: 3,
33	    vaultIdeas: [],
34	    unsubscribeVault: null,
35	
36	    // Simulator State
37	    simState: 1,
38	    simMessages: [],
39	    simInput: '',
40	    simFilterStrength: 3,
41	    
42	    // Calculator variables
43	    hoursWasted: 5,
44	    milesDriven: 50,
45	    hourlyRate: 45,
46	    fuelCost: 0.45,
47	    showModal: null,
48	    get adminDebt() { return Math.round((this.hoursWasted * this.hourlyRate + this.milesDriven * this.fuelCost) * 52); },
49	    
50	    // Dashboard variables
51	    activeTab: 'money', // 'money' | 'safety' | 'business'
52	    leads: [],
53	    isLoadingLeads: false,
54	    selectedLead: null,
55	    isLeadModalOpen: false,
56	    unsubscribeLeads: null,
57	    
58	    get moneyLeads() {
59	        return this.leads.filter((l: any) => l.status === 'qualified');
60	    },
61	
62	    get safetyLeads() {
63	        return this.leads.filter((l: any) => l.status === 'archived');
64	    },
65	
66	    init() {
67	      window.addEventListener('popstate', () => {
68	        this.route = window.location.pathname;
69	        this.handleRouteLogic();
70	      });
71	      
72	      this.handleRouteLogic();
73	    },
74	
75	    handleRouteLogic() {
76	      if (this.route === '/dashboard') {
77	        this.subscribeLeads();
78	      } else {
79	        this.unsubscribeLeadsListener();
80	      }
81	
82	      if (this.route === '/vault') {
83	        this.subscribeVault();
84	      } else {
85	        this.unsubscribeVaultListener();
86	      }
87	
88	      if (this.route === '/') {
89	        this.initSimulator();
90	      }
91	    },
92	    
93	    navigate(path: string) {
94	      window.history.pushState({}, '', path);
95	      this.route = path;
96	      window.scrollTo(0, 0);
97	      this.handleRouteLogic();
98	    },
99	
100	    unsubscribeLeadsListener() {
101	        if (this.unsubscribeLeads) {
102	            this.unsubscribeLeads();
103	            this.unsubscribeLeads = null;
104	        }
105	    },
106	
107	    unsubscribeVaultListener() {
108	        if (this.unsubscribeVault) {
109	            this.unsubscribeVault();
110	            this.unsubscribeVault = null;
111	        }
112	    },
113	    
114	    subscribeLeads() {
115	      this.isLoadingLeads = true;
116	      try {
117	        const leadsRef = collection(db, 'leads');
118	        this.unsubscribeLeads = onSnapshot(leadsRef, (snapshot) => {
119	            this.leads = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
120	            this.isLoadingLeads = false;
121	        }, (error) => {
122	            console.error("Failed to fetch leads:", error);
123	            this.isLoadingLeads = false;
124	        });
125	      } catch (err) {
126	        console.error("Failed to setup leads listener:", err);
127	        this.isLoadingLeads = false;
128	      }
129	    },
130	
131	    subscribeVault() {
132	      try {
133	        const vaultRef = collection(db, 'vault_ideas');
134	        this.unsubscribeVault = onSnapshot(vaultRef, (snapshot) => {
135	            this.vaultIdeas = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }))
136	                .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
137	        });
138	      } catch (err) {
139	        console.error("Failed to setup vault listener:", err);
140	      }
141	    },
142	
143	    async addVaultIdea() {
144	        if (!this.newVaultIdea.trim()) return;
145	        try {
146	            await addDoc(collection(db, 'vault_ideas'), {
147	                text: this.newVaultIdea,
148	                phase: parseInt(this.newVaultPhase) || 3,
149	                createdAt: new Date().toISOString()
150	            });
151	            this.newVaultIdea = '';
152	            this.newVaultPhase = 3;
153	        } catch (err) {
154	            console.error("Failed to add idea:", err);
155	        }
156	    },
157	
158	    openLead(lead: any) {
159	        this.selectedLead = lead;
160	        this.isLeadModalOpen = true;
161	    },
162	
163	    closeLead() {
164	        this.isLeadModalOpen = false;
165	        setTimeout(() => { this.selectedLead = null; }, 300);
166	    },
167	
168	    async reclaimLead(leadId: string) {
169	        try {
170	            const leadRef = doc(db, 'leads', leadId);
171	            await updateDoc(leadRef, {
172	                status: 'qualified',
173	                reclaimedAt: new Date().toISOString()
174	            });
175	        } catch (err) {
176	            console.error("Failed to reclaim lead:", err);
177	        }
178	    },
179	
180	    async simulateLead() {
181	        try {
182	            const leadsRef = collection(db, 'leads');
183	            const randomId = Math.floor(Math.random() * 1000);
184	            const isQualified = Math.random() > 0.3; // 70% chance of being qualified
185	            
186	            await addDoc(leadsRef, {
187	                customerName: `Test Customer ${randomId}`,
188	                jobDescription: isQualified ? 'Need a complete rewire of the kitchen. About 4 double sockets and 6 spotlights. Ready to start next week.' : 'Need some electrical work done, not sure what exactly.',
189	                postcode: isQualified ? 'B14 7TE' : '',
190	                budget: isQualified ? '1500' : '',
191	                status: isQualified ? 'qualified' : 'archived',
192	                createdAt: new Date().toISOString()
193	            });
194	        } catch (err) {
195	            console.error("Failed to simulate lead:", err);
196	        }
197	    },
198	
199	    // Simulator Logic
200	    initSimulator() {
201	        this.simState = 1;
202	        this.simMessages = [
203	            { sender: 'bot', text: "Hi, I'm the automated assistant for this business. To get you a quote faster, I need a few details." }
204	        ];
205	    },
206	
207	    async sendSimMessage(text: string) {
208	        if (!text || !text.trim()) return;
209	        
210	        const userMsg = text;
211	        this.simMessages.push({ sender: 'user', text: userMsg });
212	
213	        // Call our backend webhook to simulate the AI
214	        try {
215	            const res = await fetch('/api/whatsapp/webhook', {
216	                method: 'POST',
217	                headers: { 'Content-Type': 'application/json' },
218	                body: JSON.stringify({
219	                    message: userMsg,
220	                    tradie_id: 'sim_123',
221	                    current_state: this.simState,
222	                    filter_strength: this.simFilterStrength,
223	                    has_media: userMsg.toLowerCase().includes('photo') || userMsg.toLowerCase().includes('pic')
224	                })
225	            });
226	            const data = await res.json();
227	            
228	            setTimeout(() => {
229	                this.simMessages.push({ sender: 'bot', text: data.reply });
230	                this.simState = data.nextState;
231	                
232	                // Auto-scroll simulator
233	                const simChat = document.getElementById('sim-chat');
234	                if (simChat) simChat.scrollTop = simChat.scrollHeight;
235	            }, 600);
236	
237	        } catch (err) {
238	            console.error("Simulator error:", err);
239	        }
240	    },
241	    
242	    async login() {
243	      this.isLoggingIn = true;
244	      this.loginError = '';
245	      
246	      try {
247	        const phoneRegex = /^\+[1-9]\d{1,14}$/;
248	        if (!phoneRegex.test(this.phoneNumber)) {
249	          throw new Error('Please enter a valid phone number in E.164 format (e.g., +447700900000)');
250	        }
251	
252	        const tradesmenRef = collection(db, 'tradesmen');
253	        const q = query(tradesmenRef, where('phoneNumber', '==', this.phoneNumber));
254	        const querySnapshot = await getDocs(q);
255	        
256	        if (!querySnapshot.empty) {
257	          this.navigate('/dashboard');
258	        } else {
259	          this.navigate('/onboarding');
260	        }
261	      } catch (err: any) {
262	        this.loginError = err.message || 'Failed to login';
263	      } finally {
264	        this.isLoggingIn = false;
265	      }
266	    },
267	
268	    nextOnboardingStep() {
269	        if (this.onboardingStep < 3) {
270	            this.onboardingStep++;
271	        }
272	    },
273	
274	    async register() {
275	      this.isLoggingIn = true;
276	      this.loginError = '';
277	      
278	      try {
279	        const tradesmenRef = collection(db, 'tradesmen');
280	        await addDoc(tradesmenRef, {
281	          phoneNumber: this.phoneNumber || '+447000000000',
282	          name: this.registerName,
283	          trade: this.registerTrade,
284	          companyName: this.registerCompany,
285	          serviceArea: this.registerArea,
286	          calloutFee: this.calloutFee,
287	          filterStrictness: this.filterStrictness,
288	          createdAt: new Date().toISOString()
289	        });
290	
291	        // Send email via backend mock
292	        await fetch('/api/onboarding/submit', {
293	            method: 'POST',
294	            headers: { 'Content-Type': 'application/json' },
295	            body: JSON.stringify({
296	                name: this.registerName,
297	                trade: this.registerTrade,
298	                phoneNumber: this.phoneNumber,
299	                calloutFee: this.calloutFee,
300	                filterStrictness: this.filterStrictness
301	            })
302	        });
303	        
304	        this.navigate('/dashboard');
305	      } catch (err: any) {
306	        this.loginError = err.message || 'Failed to register';
307	      } finally {
308	        this.isLoggingIn = false;
309	      }
310	    }
311	  }));
312	});
313	
314	Alpine.start();
