33	          nextState = 2;
34	        }
35	        break;
36	      case 2: // State 2: The Vet
37	        if (message.length > 20 && message.match(/[A-Z]{1,2}[0-9][A-Z0-9]? ?[0-9][A-Z]{2}/i)) {
38	          if (filter_strength <= 2) {
