2	service cloud.firestore {
3	  match /databases/{database}/documents {
4	
5	    // ===============================================================
6	    // Assumed Data Model
7	    // ===============================================================
8	    //
9	    // Collection: tradesmen
10	    // Document ID: auto-generated
11	    // Fields:
12	    //   - uid: string (required, immutable) - Firebase Auth UID
13	    //   - email: string (required) - User email
14	    //   - name: string (required) - Full name
15	    //   - trade: string - Trade type
16	    //   - phoneNumber: string - Mobile number
17	    //   - isActive: bool - Account activation status
18	    //   - ... settings (calloutFee, filterStrictness, etc.)
19	    //
20	    // Collection: customers/{uid}/subscriptions
21	    // Document ID: Stripe subscription ID
22	    // Fields:
23	    //   - status: string - active, trialing, etc.
24	    //   - role: string - user role
25	    //
26	    // Collection: leads
27	    // Document ID: auto-generated
28	    // Fields:
29	    //   - status: string - qualified, archived
30	    //   - customerName: string
31	    //   - postcode: string
32	    //   - ... job details
33	    //
34	    // ===============================================================
35	
36	    // ===============================================================
37	    // Helper Functions
38	    // ===============================================================
39	    
40	    function isAuthenticated() {
41	      return request.auth != null;
42	    }
43	
44	    function isOwner(userId) {
45	      return isAuthenticated() && request.auth.uid == userId;
46	    }
47	
48	    function isAdmin() {
49	      return isAuthenticated() &&
50	        (get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin' ||
51	          (request.auth.token.email == "manazoid4@gmail.com" && request.auth.token.email_verified == true));
52	    }
53	
54	    function isValidTradesman(data) {
55	      return data.uid is string && data.uid.size() > 0 &&
56	             data.email is string && data.email.size() > 0 &&
57	             data.name is string && data.name.size() > 0 &&
58	             data.name.size() < 100;
59	    }
60	
61	    // ===============================================================
62	    // Rules
63	    // ===============================================================
64	
65	    // Tradesmen Profiles
66	    match /tradesmen/{docId} {
67	      allow read: if isAuthenticated() && (request.auth.uid == resource.data.uid || isAdmin());
68	      allow create: if isAuthenticated() && isValidTradesman(request.resource.data) && (request.resource.data.uid == request.auth.uid || isAdmin());
69	      allow update: if isAuthenticated() && isValidTradesman(request.resource.data) && 
70	                    (request.auth.uid == resource.data.uid && request.resource.data.uid == resource.data.uid || isAdmin());
71	      allow delete: if isAdmin();
72	    }
73	
74	    // Stripe Extension: Customers & Subscriptions
75	    match /customers/{uid} {
76	      allow read: if isOwner(uid) || isAdmin();
77	      
78	      match /subscriptions/{subId} {
79	        allow read: if isOwner(uid) || isAdmin();
80	      }
81	      
82	      match /payments/{paymentId} {
83	        allow read: if isOwner(uid) || isAdmin();
84	      }
85	    }
86	
87	    // Products & Prices (often used by Stripe extension)
88	    match /products/{id} {
89	      allow read: if true;
90	      match /prices/{id} {
91	        allow read: if true;
92	      }
93	    }
94	
95	    // Leads
96	    match /leads/{leadId} {
97	      // Allow authenticated users to read leads. 
98	      allow read: if isAuthenticated();
99	      // Allow authenticated users to create a lead (used by simulator)
100	      allow create: if isAuthenticated();
101	      // Allow update for status conversion
102	      allow update: if isAuthenticated() && request.resource.data.diff(resource.data).affectedKeys().hasOnly(['status']);
103	      allow write: if isAdmin();
104	    }
105	
106	    // Jobs
107	    match /jobs/{jobId} {
108	      allow read: if isAuthenticated() && (request.auth.uid == resource.data.uid || isAdmin());
109	      allow create: if isAuthenticated() && request.resource.data.uid == request.auth.uid;
110	      allow update: if isAuthenticated() && request.auth.uid == resource.data.uid && request.resource.data.uid == resource.data.uid;
111	      allow delete: if isAdmin();
112	    }
113	
114	    // Waitlist — public write, admin read only
115	    match /waitlist/{docId} {
116	      allow create: if request.resource.data.email is string &&
117	                       request.resource.data.email.size() > 0 &&
118	                       request.resource.data.email.size() < 254;
119	      allow read: if isAdmin();
120	    }
121	
122	    // Blueprint ideas — admin only
123	    match /blueprint/{docId} {
124	      allow read, write: if isAdmin();
125	    }
126	
127	    // Mail collection — backend server only (via Firebase Admin SDK)
128	    // The Trigger Email extension reads from here and sends emails
129	    match /mail/{docId} {
130	      allow read, write: if false; // Controlled by backend only
131	    }
132	
133	    // Default deny
134	    match /{document=**} {
135	      allow read, write: if false;
136	    }
137	  }
138	}
