  --color-charcoal: #1e293b;
}

@layer utilities {
  .glow-cyan {
    box-shadow: 0 0 15px rgba(34, 211, 238, 0.3);
  }
  .glow-orange {
    box-shadow: 0 0 20px rgba(245, 158, 11, 0.4);
